/** tauri-specta globals **/

import { Channel as TAURI_CHANNEL } from '@tauri-apps/api/core';
import * as TAURI_API_EVENT from '@tauri-apps/api/event';
import { type WebviewWindow as __WebviewWindow__ } from '@tauri-apps/api/webviewWindow';

import { invoke as TAURI_INVOKE } from './generatedInvoke';

type __EventObj__<T> = {
    listen: (
        cb: TAURI_API_EVENT.EventCallback<T>
    ) => ReturnType<typeof TAURI_API_EVENT.listen<T>>;
    once: (
        cb: TAURI_API_EVENT.EventCallback<T>
    ) => ReturnType<typeof TAURI_API_EVENT.once<T>>;
    emit: null extends T
        ? (payload?: T) => ReturnType<typeof TAURI_API_EVENT.emit>
        : (payload: T) => ReturnType<typeof TAURI_API_EVENT.emit>;
};

export type Result<T, E> =
    | { status: 'ok'; data: T }
    | { status: 'error'; error: E };

function __makeEvents__<T extends Record<string, unknown>>(
    mappings: Record<keyof T, string>
) {
    return new Proxy(
        {} as unknown as {
            [K in keyof T]: __EventObj__<T[K]> & {
                (handle: __WebviewWindow__): __EventObj__<T[K]>;
            };
        },
        {
            get: (_, event) => {
                const name = mappings[event as keyof T];

                return new Proxy(
                    (() => {}) as (...args: unknown[]) => unknown,
                    {
                        apply: (_, __, [window]: [__WebviewWindow__]) => ({
                            listen: (
                                arg: TAURI_API_EVENT.EventCallback<unknown>
                            ) => window.listen<unknown>(name, arg),
                            once: (
                                arg: TAURI_API_EVENT.EventCallback<unknown>
                            ) => window.once<unknown>(name, arg),
                            emit: (arg: unknown) => window.emit(name, arg)
                        }),
                        get: (_, command: keyof __EventObj__<unknown>) => {
                            switch (command) {
                                case 'listen':
                                    return (
                                        arg: TAURI_API_EVENT.EventCallback<unknown>
                                    ) =>
                                        TAURI_API_EVENT.listen<unknown>(
                                            name,
                                            arg
                                        );
                                case 'once':
                                    return (
                                        arg: TAURI_API_EVENT.EventCallback<unknown>
                                    ) =>
                                        TAURI_API_EVENT.once<unknown>(
                                            name,
                                            arg
                                        );
                                case 'emit':
                                    return (arg: unknown) =>
                                        TAURI_API_EVENT.emit(name, arg);
                            }
                        }
                    }
                );
            }
        }
    );
}
